'use client';

import { useCallback, useMemo } from 'react';
import type React from 'react';

import { draftSubmitSchema } from '@/features/drafter/validations/draft-form';
import type { ProductImageManagerController } from '@/shared/contracts/product-image-manager';
import {
  ProductImagesTabContent,
  ProductImagesTabProvider,
} from '@/features/products/forms.public';
import {
  ProductFormImageContext,
  type ProductFormImageContextType,
} from '@/features/products/context/ProductFormImageContext';
import type { ProductParameterValue } from '@/shared/contracts/products/product';
import type { CreateProductDraftInput } from '@/shared/contracts/products/drafts';
import { IconSelector } from '@/shared/lib/icons';
import { AppModal } from '@/shared/ui/feedback.public';
import { Tabs, TabsContent, TabsList, TabsTrigger, useToast, Card } from '@/shared/ui/primitives.public';
import { LoadingState } from '@/shared/ui/navigation-and-layout.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';
import { validateFormData } from '@/shared/validations/form-validation';

import {
  DraftCreatorFormProvider,
  type DraftCreatorFormContextValue,
} from './DraftCreatorFormContext';
import { DraftCreatorDetailsTab, DraftCreatorParametersTab } from './DraftCreatorFormFields';
import { useOptionalDrafterActions, useOptionalDrafterState } from '../context/DrafterContext';
import { useDraftCreatorForm } from '../hooks/useDraftCreatorForm';

const DEFAULT_ICON_COLOR = '#60a5fa';
const TOTAL_IMAGE_SLOTS = 15;

const fileToDataUrl = (file: File): Promise<string> =>
  new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = () => reject(new Error('Failed to convert image to data URL.'));
    reader.readAsDataURL(file);
  });

const normalizeIconColor = (value: string | null | undefined): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  const HEX_PATTERN = /^#[0-9a-fA-F]{6}$/;
  if (HEX_PATTERN.test(trimmed) === false) return null;
  return trimmed.toLowerCase();
};

export function DraftCreator({
  draftId: propDraftId,
  onSaveSuccess: propOnSaveSuccess,
  active: propActive,
  onActiveChange,
}: {
  draftId?: string | null;
  onSaveSuccess?: () => void;
  active?: boolean;
  onActiveChange?: (value: boolean) => void;
  onCancel?: () => void;
} = {}): React.JSX.Element {
  const { toast } = useToast();
  const stateContext = useOptionalDrafterState();
  const actionsContext = useOptionalDrafterActions();

  const draftId = propDraftId ?? (stateContext?.editingDraftId ?? null);
  const handleSaveSuccess =
    propOnSaveSuccess ?? actionsContext?.handleSaveSuccess ?? ((): void => {});
  const formRef = stateContext?.formRef;

  const form = useDraftCreatorForm(draftId, handleSaveSuccess, propActive, onActiveChange);
  const { state, queries, images, metadata } = form;

  const serializeDraftImageLinks = useCallback(async (): Promise<string[]> => {
    const promises: Promise<string | null>[] = [];

    for (let i = 0; i < TOTAL_IMAGE_SLOTS; i += 1) {
      const base64 = images.imageBase64s[i]?.trim();
      if (base64 !== undefined && base64 !== '') {
        promises.push(Promise.resolve(base64));
        continue;
      }
      const link = images.imageLinks[i]?.trim();
      if (link !== undefined && link !== '') {
        promises.push(Promise.resolve(link));
        continue;
      }
      const slot = images.imageSlots[i];
      if (slot === undefined || slot === null) {
        promises.push(Promise.resolve(null));
        continue;
      }
      if (slot.type === 'existing') {
        const path = slot.data?.filepath?.trim();
        promises.push(Promise.resolve(path !== undefined && path !== '' ? path : null));
        continue;
      }

      promises.push(
        fileToDataUrl(slot.data as File).catch((err) => {
          logClientCatch(err, { source: 'DraftCreator', action: 'serializeDraftImage', draftId });
          return null;
        })
      );
    }
    const results = await Promise.all(promises);
    return results.filter((r): r is string => r !== null && r !== '');
  }, [draftId, images]);

  const handleSave = async (): Promise<void> => {
    const formData = {
      name: state.name,
      draftKind: state.draftKind,
      scrapeProfileId: state.scrapeProfileId,
      iconColorMode: state.iconColorMode,
      iconColor: state.iconColor,
      openProductFormTab: state.openProductFormTab,
      stock: state.stock,
    };
    const validation = validateFormData(draftSubmitSchema, formData, 'Draft form is invalid.');
    if (validation.success === false) {
      toast(validation.firstError, { variant: 'error' });
      return;
    }

    try {
      const imgLinks = await serializeDraftImageLinks();
      const input: CreateProductDraftInput = {
        name: state.name.trim(),
        draftKind: state.draftKind,
        scrapeProfileId:
          state.draftKind === 'scrape_template' && state.scrapeProfileId !== null
            ? state.scrapeProfileId
            : null,
        description: state.description.trim() !== '' ? state.description.trim() : null,
        sku: state.sku.trim() !== '' ? state.sku.trim() : null,
        ean: state.ean.trim() !== '' ? state.ean.trim() : null,
        gtin: state.gtin.trim() !== '' ? state.gtin.trim() : null,
        asin: state.asin.trim() !== '' ? state.asin.trim() : null,
        name_en: state.nameEn.trim() !== '' ? state.nameEn.trim() : null,
        name_pl: state.namePl.trim() !== '' ? state.namePl.trim() : null,
        name_de: state.nameDe.trim() !== '' ? state.nameDe.trim() : null,
        description_en: state.descEn.trim() !== '' ? state.descEn.trim() : null,
        description_pl: state.descPl.trim() !== '' ? state.descPl.trim() : null,
        description_de: state.descDe.trim() !== '' ? state.descDe.trim() : null,
        weight: state.weight !== '' ? parseFloat(state.weight) : null,
        sizeLength: state.sizeLength !== '' ? parseFloat(state.sizeLength) : null,
        sizeWidth: state.sizeWidth !== '' ? parseFloat(state.sizeWidth) : null,
        length: state.length !== '' ? parseFloat(state.length) : null,
        price: state.price !== '' ? parseFloat(state.price) : null,
        supplierName: state.supplierName.trim() !== '' ? state.supplierName.trim() : null,
        supplierLink: state.supplierLink.trim() !== '' ? state.supplierLink.trim() : null,
        priceComment: state.priceComment.trim() !== '' ? state.priceComment.trim() : null,
        stock: validation.data.stock,
        catalogIds: state.selectedCatalogIds,
        categoryId: state.selectedCategoryId,
        tagIds: state.selectedTagIds,
        producerIds: state.selectedProducerIds,
        parameters: state.parameterValues
          .map((e: ProductParameterValue): ProductParameterValue => ({
            parameterId: e.parameterId?.trim(),
            value: typeof e.value === 'string' ? e.value.trim() : '',
            ...(e.valuesByLanguage !== undefined ? { valuesByLanguage: e.valuesByLanguage } : {}),
            ...(e.skipParameterInference === true ? { skipParameterInference: true } : {}),
          }))
          .filter(
            (e): e is ProductParameterValue & { parameterId: string } =>
              e.parameterId !== undefined && e.parameterId !== ''
          ),
        active: state.active,
        validatorEnabled: state.validatorEnabled,
        formatterEnabled: state.validatorEnabled ? state.formatterEnabled : false,
        icon: state.icon,
        iconColorMode: state.iconColorMode,
        iconColor: state.iconColorMode === 'custom' ? normalizeIconColor(state.iconColor) ?? DEFAULT_ICON_COLOR : null,
        openProductFormTab: state.openProductFormTab,
        imageLinks: imgLinks,
        baseProductId: state.baseProductId.trim() !== '' ? state.baseProductId.trim() : null,
      };

      if (draftId !== null) {
        await queries.updateDraftMutation.mutateAsync({ id: draftId, data: input });
      } else {
        await queries.createDraftMutation.mutateAsync(input);
      }

      toast(draftId !== null ? 'Draft updated successfully' : 'Draft created successfully', { variant: 'success' });
      handleSaveSuccess();
    } catch (err) {
      logClientCatch(err, { source: 'DraftCreator', action: 'saveDraft', draftId });
      toast('Failed to save draft', { variant: 'error' });
    }
  };

  const imageManagerController = useMemo<ProductImageManagerController>(
    () => ({
      imageSlots: images.imageSlots,
      imageLinks: images.imageLinks,
      imageBase64s: images.imageBase64s,
      setImageLinkAt: images.setImageLinkAt,
      setImageBase64At: images.setImageBase64At,
      handleSlotImageChange: images.handleSlotImageChange,
      handleSlotFileSelect: images.handleSlotFileSelect,
      handleSlotDisconnectImage: images.handleSlotDisconnectImage,
      setShowFileManager: images.setShowFileManager,
      swapImageSlots: images.swapImageSlots,
      setImagesReordering: images.setImagesReordering,
      uploadError: null,
    }),
    [images]
  );

  const productFormImageContextValue = useMemo<ProductFormImageContextType>(
    () => ({
      imageSlots: images.imageSlots,
      imageLinks: images.imageLinks,
      imageBase64s: images.imageBase64s,
      productId: null,
      uploading: false,
      uploadError: null,
      uploadSuccess: false,
      showFileManager: images.showFileManager,
      setShowFileManager: images.setShowFileManager,
      handleSlotImageChange: images.handleSlotImageChange,
      handleSlotFileSelect: images.handleSlotFileSelect,
      handleSlotDisconnectImage: images.handleSlotDisconnectImage,
      handleMultiImageChange: images.handleMultiImageChange,
      handleMultiFileSelect: images.handleMultiFileSelect,
      swapImageSlots: images.swapImageSlots,
      setImageLinkAt: images.setImageLinkAt,
      setImageBase64At: images.setImageBase64At,
      setImagesReordering: images.setImagesReordering,
      refreshImagesFromProduct: images.refreshFromProduct,
    }),
    [images]
  );

  const resolvedIconColor = normalizeIconColor(state.iconColor) ?? DEFAULT_ICON_COLOR;

  const contextValue = useMemo<DraftCreatorFormContextValue>(
    () => ({
      ...state,
      ...queries,
      ...metadata,
      ...images,
      resolvedIconColor,
      openIconLibrary: () => state.setIsIconLibraryOpen(true),
      imageManagerController,
    }),
    [state, queries, metadata, images, resolvedIconColor, imageManagerController]
  );

  if (queries.draftQuery.isLoading) {
    return (
      <Card variant='subtle' padding='lg' className='flex items-center justify-center min-h-[400px]'>
        <LoadingState message='Loading draft configuration...' />
      </Card>
    );
  }

  return (
    <>
      <DraftCreatorFormProvider value={contextValue}>
        <form
          ref={formRef}
          onSubmit={(e: React.FormEvent): void => {
            e.preventDefault();
            handleSave().catch(() => {});
          }}
          className='space-y-6'
        >
          <div className='space-y-6'>
            <Tabs defaultValue='details' className='w-full'>
              <TabsList className='mb-6' aria-label='Draft creator tabs'>
                <TabsTrigger value='details'>Details</TabsTrigger>
                <TabsTrigger value='images'>Images</TabsTrigger>
                <TabsTrigger value='parameters'>Parameters</TabsTrigger>
              </TabsList>
              <TabsContent value='details' className='mt-0 space-y-6'>
                <DraftCreatorDetailsTab />
              </TabsContent>
              <TabsContent value='images' className='mt-0 space-y-4'>
                <ProductFormImageContext.Provider value={productFormImageContextValue}>
                  <ProductImagesTabProvider
                    value={{
                      showFileManager: images.showFileManager,
                      onShowFileManager: images.setShowFileManager,
                      onSelectFiles: images.handleMultiFileSelect,
                      inlineFileManager: true,
                      imageManagerController,
                    }}
                  >
                    <ProductImagesTabContent />
                  </ProductImagesTabProvider>
                </ProductFormImageContext.Provider>
              </TabsContent>
              <TabsContent value='parameters' className='mt-0 space-y-4'>
                <DraftCreatorParametersTab />
              </TabsContent>
            </Tabs>
          </div>
        </form>
      </DraftCreatorFormProvider>

      <AppModal
        open={state.isIconLibraryOpen}
        onClose={() => state.setIsIconLibraryOpen(false)}
        title='Choose Icon'
        size='xl'
        className='md:min-w-[72rem] max-w-[80rem]'
        bodyClassName='h-[76vh]'
      >
        <IconSelector
          value={state.icon}
          onChange={(next) => {
            state.setIcon(next);
            state.setIsIconLibraryOpen(false);
          }}
          columns={12}
          showSearch
          helperText='Search and pick an icon. Selecting an icon applies it immediately.'
        />
      </AppModal>
    </>
  );
}

'use client';

import { useMemo } from 'react';

import type { ProductImageManagerController } from '@/shared/contracts/product-image-manager';
import type { ImageFileSelection } from '@/shared/contracts/files';
import type { CatalogRecord } from '@/shared/contracts/products/catalogs';
import type { Producer } from '@/shared/contracts/products/producers';
import type { ProductCategory } from '@/shared/contracts/products/categories';
import type { ProductParameter } from '@/shared/contracts/products/parameters';
import type { ProductParameterValue } from '@/shared/contracts/products/product';
import type { ProductTag } from '@/shared/contracts/products/tags';
import type { ProductDraftKind, ProductDraftOpenFormTab } from '@/shared/contracts/products/drafts';
import { internalError } from '@/shared/errors/app-error';
import { createStrictContext } from '@/shared/lib/react/createStrictContext';

const createDraftCreatorStrictContext = <T,>(hookName: string, displayName: string) =>
  createStrictContext<T>({
    hookName,
    providerName: 'a DraftCreatorFormProvider',
    displayName,
    errorFactory: internalError,
  });

// --- Basic Info Context ---
export interface DraftCreatorBasicInfo {
  name: string;
  setName: (next: string) => void;
  draftKind: ProductDraftKind;
  setDraftKind: (next: ProductDraftKind) => void;
  scrapeProfileId: string | null;
  setScrapeProfileId: (next: string | null) => void;
  description: string;
  setDescription: (next: string) => void;
  validatorEnabled: boolean;
  setValidatorEnabled: (next: boolean) => void;
  formatterEnabled: boolean;
  setFormatterEnabled: (next: boolean) => void;
  icon: string | null;
  setIcon: (next: string | null) => void;
  iconColorMode: 'theme' | 'custom';
  setIconColorMode: (next: 'theme' | 'custom') => void;
  iconColor: string;
  setIconColor: (next: string) => void;
  openProductFormTab: ProductDraftOpenFormTab;
  setOpenProductFormTab: (next: ProductDraftOpenFormTab) => void;
  resolvedIconColor: string;
  openIconLibrary: () => void;
}
const basicInfoContextResult = createDraftCreatorStrictContext<DraftCreatorBasicInfo>(
  'useDraftCreatorBasicInfo',
  'DraftCreatorBasicInfoContext'
);
export const BasicInfoContext = basicInfoContextResult.Context;
export const useDraftCreatorBasicInfo = basicInfoContextResult.useStrictContext;

// --- Product Data Context ---
export interface DraftCreatorProductData {
  sku: string;
  setSku: (next: string) => void;
  identifierType: 'ean' | 'gtin' | 'asin';
  setIdentifierType: (next: 'ean' | 'gtin' | 'asin') => void;
  ean: string;
  setEan: (next: string) => void;
  gtin: string;
  setGtin: (next: string) => void;
  asin: string;
  setAsin: (next: string) => void;
  weight: string;
  setWeight: (next: string) => void;
  sizeLength: string;
  setSizeLength: (next: string) => void;
  sizeWidth: string;
  setSizeWidth: (next: string) => void;
  length: string;
  setLength: (next: string) => void;
  nameEn: string;
  setNameEn: (next: string) => void;
  namePl: string;
  setNamePl: (next: string) => void;
  nameDe: string;
  setNameDe: (next: string) => void;
  descEn: string;
  setDescEn: (next: string) => void;
  descPl: string;
  setDescPl: (next: string) => void;
  descDe: string;
  setDescDe: (next: string) => void;
  price: string;
  setPrice: (next: string) => void;
  stock: string;
  setStock: (next: string) => void;
  supplierName: string;
  setSupplierName: (next: string) => void;
  supplierLink: string;
  setSupplierLink: (next: string) => void;
  priceComment: string;
  setPriceComment: (next: string) => void;
  baseProductId: string;
  setBaseProductId: (next: string) => void;
}
const productDataContextResult = createDraftCreatorStrictContext<DraftCreatorProductData>(
  'useDraftCreatorProductData',
  'DraftCreatorProductDataContext'
);
export const ProductDataContext = productDataContextResult.Context;
export const useDraftCreatorProductData = productDataContextResult.useStrictContext;

// --- Metadata Context ---
export interface DraftCreatorMetadata {
  catalogs: CatalogRecord[];
  selectedCatalogIds: string[];
  setSelectedCatalogIds: (nextIds: string[]) => void;
  categories: ProductCategory[];
  categoryLoading: boolean;
  selectedCategoryId: string | null;
  setSelectedCategoryId: (nextId: string | null) => void;
  tags: ProductTag[];
  tagLoading: boolean;
  selectedTagIds: string[];
  setSelectedTagIds: (nextIds: string[]) => void;
  producers: Producer[];
  producersLoading: boolean;
  selectedProducerIds: string[];
  setSelectedProducerIds: (nextIds: string[]) => void;
}
const metadataContextResult = createDraftCreatorStrictContext<DraftCreatorMetadata>(
  'useDraftCreatorMetadata',
  'DraftCreatorMetadataContext'
);
export const MetadataContext = metadataContextResult.Context;
export const useDraftCreatorMetadata = metadataContextResult.useStrictContext;

// --- Images Context ---
export interface DraftCreatorImages {
  showFileManager: boolean;
  setShowFileManager: (show: boolean) => void;
  handleMultiFileSelect: (files: ImageFileSelection[]) => void;
  imageManagerController: ProductImageManagerController;
}
const imagesContextResult = createDraftCreatorStrictContext<DraftCreatorImages>(
  'useDraftCreatorImages',
  'DraftCreatorImagesContext'
);
export const ImagesContext = imagesContextResult.Context;
export const useDraftCreatorImages = imagesContextResult.useStrictContext;

// --- Parameters Context ---
export interface DraftCreatorParameters {
  parameters: ProductParameter[];
  parametersLoading: boolean;
  parameterValues: ProductParameterValue[];
  addParameterValue: () => void;
  updateParameterId: (index: number, parameterId: string) => void;
  updateParameterValue: (index: number, value: string) => void;
  removeParameterValue: (index: number) => void;
}
const parametersContextResult = createDraftCreatorStrictContext<DraftCreatorParameters>(
  'useDraftCreatorParameters',
  'DraftCreatorParametersContext'
);
export const ParametersContext = parametersContextResult.Context;
export const useDraftCreatorParameters = parametersContextResult.useStrictContext;

// --- Context Aggregator ---
export interface DraftCreatorFormContextValue
  extends
    DraftCreatorBasicInfo,
    DraftCreatorProductData,
    DraftCreatorMetadata,
    DraftCreatorImages,
    DraftCreatorParameters {}

export function DraftCreatorFormProvider({
  value,
  children,
}: {
  value: DraftCreatorFormContextValue;
  children: React.ReactNode;
}): React.JSX.Element {
  const basicInfo = useMemo(
    () => ({
      name: value.name,
      setName: value.setName,
      draftKind: value.draftKind,
      setDraftKind: value.setDraftKind,
      scrapeProfileId: value.scrapeProfileId,
      setScrapeProfileId: value.setScrapeProfileId,
      description: value.description,
      setDescription: value.setDescription,
      validatorEnabled: value.validatorEnabled,
      setValidatorEnabled: value.setValidatorEnabled,
      formatterEnabled: value.formatterEnabled,
      setFormatterEnabled: value.setFormatterEnabled,
      icon: value.icon,
      setIcon: value.setIcon,
      iconColorMode: value.iconColorMode,
      setIconColorMode: value.setIconColorMode,
      iconColor: value.iconColor,
      setIconColor: value.setIconColor,
      openProductFormTab: value.openProductFormTab,
      setOpenProductFormTab: value.setOpenProductFormTab,
      resolvedIconColor: value.resolvedIconColor,
      openIconLibrary: value.openIconLibrary,
    }),
    [value]
  );

  const productData = useMemo(
    () => ({
      sku: value.sku,
      setSku: value.setSku,
      identifierType: value.identifierType,
      setIdentifierType: value.setIdentifierType,
      ean: value.ean,
      setEan: value.setEan,
      gtin: value.gtin,
      setGtin: value.setGtin,
      asin: value.asin,
      setAsin: value.setAsin,
      weight: value.weight,
      setWeight: value.setWeight,
      sizeLength: value.sizeLength,
      setSizeLength: value.setSizeLength,
      sizeWidth: value.sizeWidth,
      setSizeWidth: value.setSizeWidth,
      length: value.length,
      setLength: value.setLength,
      nameEn: value.nameEn,
      setNameEn: value.setNameEn,
      namePl: value.namePl,
      setNamePl: value.setNamePl,
      nameDe: value.nameDe,
      setNameDe: value.setNameDe,
      descEn: value.descEn,
      setDescEn: value.setDescEn,
      descPl: value.descPl,
      setDescPl: value.setDescPl,
      descDe: value.descDe,
      setDescDe: value.setDescDe,
      price: value.price,
      setPrice: value.setPrice,
      stock: value.stock,
      setStock: value.setStock,
      supplierName: value.supplierName,
      setSupplierName: value.setSupplierName,
      supplierLink: value.supplierLink,
      setSupplierLink: value.setSupplierLink,
      priceComment: value.priceComment,
      setPriceComment: value.setPriceComment,
      baseProductId: value.baseProductId,
      setBaseProductId: value.setBaseProductId,
    }),
    [value]
  );

  const metadata = useMemo(
    () => ({
      catalogs: value.catalogs,
      selectedCatalogIds: value.selectedCatalogIds,
      setSelectedCatalogIds: value.setSelectedCatalogIds,
      categories: value.categories,
      categoryLoading: value.categoryLoading,
      selectedCategoryId: value.selectedCategoryId,
      setSelectedCategoryId: value.setSelectedCategoryId,
      tags: value.tags,
      tagLoading: value.tagLoading,
      selectedTagIds: value.selectedTagIds,
      setSelectedTagIds: value.setSelectedTagIds,
      producers: value.producers,
      producersLoading: value.producersLoading,
      selectedProducerIds: value.selectedProducerIds,
      setSelectedProducerIds: value.setSelectedProducerIds,
    }),
    [value]
  );

  const images = useMemo(
    () => ({
      showFileManager: value.showFileManager,
      setShowFileManager: value.setShowFileManager,
      handleMultiFileSelect: value.handleMultiFileSelect,
      imageManagerController: value.imageManagerController,
    }),
    [value]
  );

  const parameters = useMemo(
    () => ({
      parameters: value.parameters,
      parametersLoading: value.parametersLoading,
      parameterValues: value.parameterValues,
      addParameterValue: value.addParameterValue,
      updateParameterId: value.updateParameterId,
      updateParameterValue: value.updateParameterValue,
      removeParameterValue: value.removeParameterValue,
    }),
    [value]
  );

  return (
    <BasicInfoContext.Provider value={basicInfo}>
      <ProductDataContext.Provider value={productData}>
        <MetadataContext.Provider value={metadata}>
          <ImagesContext.Provider value={images}>
            <ParametersContext.Provider value={parameters}>{children}</ParametersContext.Provider>
          </ImagesContext.Provider>
        </MetadataContext.Provider>
      </ProductDataContext.Provider>
    </BasicInfoContext.Provider>
  );
}

'use client';

import { useQuery } from '@tanstack/react-query';
import { useMemo } from 'react';

import {
  CatalogMultiSelectField,
  CategorySingleSelectField,
  ProducerMultiSelectField,
  ProductMetadataFieldProvider,
  TagMultiSelectField,
} from '@/features/products/forms.public';
import type { LabeledOptionDto } from '@/shared/contracts/base';
import type { ProductParameter } from '@/shared/contracts/products/parameters';
import type { ProductParameterValue } from '@/shared/contracts/products/product';
import {
  PRODUCT_DRAFT_KIND_OPTIONS,
  PRODUCT_DRAFT_OPEN_FORM_TAB_OPTIONS,
} from '@/shared/contracts/products/drafts';
import { type ProductDraftKind, type ProductDraftOpenFormTab } from '@/shared/contracts/products';
import type { ProductScrapeProfilesListResponse } from '@/shared/contracts/products/scrape-profiles';
import { ICON_LIBRARY_MAP } from '@/shared/lib/icons';
import { api } from '@/shared/lib/api-client';
import { Button, Input, Textarea, Card } from '@/shared/ui/primitives.public';
import { SelectSimple, FormField, FormSection, ToggleRow } from '@/shared/ui/forms-and-actions.public';
import { CompactEmptyState, UI_CENTER_ROW_SPACED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';

import {
  useDraftCreatorBasicInfo,
  useDraftCreatorProductData,
  useDraftCreatorMetadata,
  useDraftCreatorParameters,
} from './DraftCreatorFormContext';
import { DraftCreatorParameterDefinitionModal } from './DraftCreatorParameterDefinitionModal';
import { DraftPlaceholderTextInput } from './DraftPlaceholderTextInput';
import { DraftStructuredProductNameInput } from './DraftStructuredProductNameInput';

const DEFAULT_ICON_COLOR = '#60a5fa';
const HEX_COLOR_PATTERN = /^#[0-9a-fA-F]{6}$/;

const normalizeIconColor = (value: string | null | undefined): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  if (!HEX_COLOR_PATTERN.test(trimmed)) return null;
  return trimmed.toLowerCase();
};

