export function DraftCreatorParametersTab(): React.JSX.Element {
  const { draftKind } = useDraftCreatorBasicInfo();
  const {
    parameters,
    parametersLoading,
    parameterValues,
    addParameterValue,
    updateParameterId,
    updateParameterValue,
    removeParameterValue,
  } = useDraftCreatorParameters();
  const placeholderDropdownEnabled = draftKind === 'scrape_template';

  const selectedParameterIds = useMemo(
    (): (string | undefined)[] =>
      parameterValues
        .map((entry: ProductParameterValue): string | undefined => entry.parameterId)
        .filter(Boolean),
    [parameterValues]
  );

  return (
    <FormSection
      title='Parameters'
      description='Set default parameter values for products created from this draft.'
      className='p-4'
      actions={
        <div className='flex flex-wrap justify-end gap-2'>
          <DraftCreatorParameterDefinitionModal />
          <Button
            type='button'
            variant='outline'
            onClick={addParameterValue}
            disabled={parametersLoading || parameters.length === 0}
          >
            Add parameter
          </Button>
        </div>
      }
    >
      {parametersLoading ? (
        <CompactEmptyState
          title='Loading parameters...'
          className='border-dashed border-border/60 py-8'
         />
      ) : parameters.length === 0 ? (
        <CompactEmptyState
          title='No parameters'
          description='No parameters available yet.'
          className='border-dashed border-border/60 py-8'
         />
      ) : parameterValues.length === 0 ? (
        <CompactEmptyState
          title='No values'
          description='Add your first parameter to start defining defaults.'
          className='border-dashed border-border/60 py-8'
         />
      ) : (
        <div className='space-y-3'>
          {parameterValues.map((entry: ProductParameterValue, index: number): React.JSX.Element => {
            const selectedParameter =
              entry.parameterId !== undefined && entry.parameterId !== ''
                ? (parameters.find(
                    (parameter: ProductParameter): boolean => parameter.id === entry.parameterId
                  ) ?? null)
                : null;
            const isLinkedParameter = selectedParameter?.linkedTitleTermType !== null &&
              selectedParameter?.linkedTitleTermType !== undefined;
            const linkedTitleTermLabel = getLinkedTitleTermLabel(
              selectedParameter?.linkedTitleTermType ?? null
            );
            const availableOptions: ProductParameter[] = parameters.filter(
              (parameter: ProductParameter): boolean =>
                (!selectedParameterIds.includes(parameter.id) || parameter.id === entry.parameterId) &&
                (!parameter.linkedTitleTermType || parameter.id === entry.parameterId)
            );
            return (
              <Card
                key={`${entry.parameterId || 'new'}-${index}`}
                variant='subtle-compact'
                padding='sm'
                className='flex flex-col gap-3 border-border bg-card/60 md:flex-row md:items-center'
              >
                <div className='w-full md:w-64'>
                  <SelectSimple
                    size='sm'
                    options={buildParameterOptions(availableOptions)}
                    value={entry.parameterId}
                    onValueChange={(value: string): void => updateParameterId(index, value)}
                    placeholder='Select parameter'
                    disabled={isLinkedParameter}
                    ariaLabel='Select parameter'
                    title='Select parameter'
                  />
                </div>
                <div className='flex-1 space-y-2'>
                  {isLinkedParameter && linkedTitleTermLabel !== null ? (
                    <div className='flex items-center gap-2 text-xs text-emerald-300'>
                      <span className='rounded-full border border-emerald-400/30 bg-emerald-500/10 px-2 py-0.5 font-medium'>
                        Synced from English Title
                      </span>
                      <span>{linkedTitleTermLabel} term</span>
                    </div>
                  ) : null}
                  <DraftPlaceholderTextInput
                    value={entry.value ?? ''}
                    onValueChange={(value): void => updateParameterValue(index, value)}
                    placeholder='Value'
                    disabled={!entry.parameterId || isLinkedParameter}
                    ariaLabel='Value'
                    title='Value'
                    placeholderDropdownEnabled={placeholderDropdownEnabled}
                  />
                </div>
                <Button
                  type='button'
                  variant='ghost'
                  onClick={(): void => removeParameterValue(index)}
                  disabled={isLinkedParameter}
                  title={
                    isLinkedParameter
                      ? 'Linked parameters are synced from English Title'
                      : 'Remove parameter'
                  }
                >
                  Remove
                </Button>
              </Card>
            );
          })}
        </div>
      )}
    </FormSection>
  );
}

import { useCallback } from 'react';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

const TOTAL_IMAGE_SLOTS = 15;

const fileToDataUrl = (file: File): Promise<string> =>
  new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = () => reject(new Error('Failed to convert image to data URL.'));
    reader.readAsDataURL(file);
  });

export const useDraftImageSerializer = (images: any, draftId?: string | null) => {
  return useCallback(async (): Promise<string[]> => {
    const promises: Promise<string | null>[] = [];

    for (let i = 0; i < TOTAL_IMAGE_SLOTS; i += 1) {
      const base64 = images.imageBase64s[i]?.trim();
      if (base64 !== undefined && base64 !== '') {
        promises.push(Promise.resolve(base64));
        continue;
      }
      const link = images.imageLinks[i]?.trim();
      if (link !== undefined && link !== '') {
        promises.push(Promise.resolve(link));
        continue;
      }
      const slot = images.imageSlots[i];
      if (slot === undefined || slot === null) {
        promises.push(Promise.resolve(null));
        continue;
      }
      if (slot.type === 'existing') {
        const path = slot.data?.filepath?.trim();
        promises.push(Promise.resolve(path !== undefined && path !== '' ? path : null));
        continue;
      }

      promises.push(
        fileToDataUrl(slot.data as File).catch((err) => {
          logClientCatch(err, { source: 'DraftCreator', action: 'serializeDraftImage', draftId });
          return null;
        })
      );
    }
    const results = await Promise.all(promises);
    return results.filter((r): r is string => r !== null && r !== '');
  }, [draftId, images]);
};

import 'server-only';

import { randomUUID } from 'crypto';

import { ObjectId, type Filter } from 'mongodb';

import {
  PRODUCT_DRAFT_KIND_OPTIONS,
  PRODUCT_DRAFT_OPEN_FORM_TAB_OPTIONS,
} from '@/shared/contracts/products/drafts';
import { type ProductDraft, type CreateProductDraftInput, type UpdateProductDraftInput, type ProductDraftKind, type ProductDraftOpenFormTab, type ProductImportSource, type ProductParameterValue } from '@/shared/contracts/products';
import { getMongoDb } from '@/shared/lib/db/mongo-client';

type MongoDraftDoc = {
  _id: string | ObjectId;
  id?: string;
  name?: string;
  draftKind?: ProductDraftKind | null;
  scrapeProfileId?: string | null;
  description?: string | null;
  sku?: string | null;
  ean?: string | null;
  gtin?: string | null;
  asin?: string | null;
  name_en?: string | null;
  name_pl?: string | null;
  name_de?: string | null;
  description_en?: string | null;
  description_pl?: string | null;
  description_de?: string | null;
  weight?: number | null;
  sizeLength?: number | null;
  sizeWidth?: number | null;
  length?: number | null;
  price?: number | null;
  supplierName?: string | null;
  supplierLink?: string | null;
  priceComment?: string | null;
  stock?: number | null;
  catalogIds?: string[];
  categoryId?: string | null;
  tagIds?: string[];
  producerIds?: string[];
  parameters?: ProductParameterValue[];
  defaultPriceGroupId?: string | null;
  active?: boolean;
  validatorEnabled?: boolean;
  formatterEnabled?: boolean;
  icon?: string | null;
  iconColorMode?: 'theme' | 'custom' | null;
  iconColor?: string | null;
  openProductFormTab?: string | null;
  imageLinks?: string[];
  baseProductId?: string | null;
  importSource?: ProductImportSource | null;
  createdAt?: Date;
  updatedAt?: Date;
};

const normalizeStringArray = (value: unknown): string[] => {
  if (!Array.isArray(value)) return [];
  const unique = new Set<string>();
  value.forEach((entry: unknown) => {
    if (typeof entry !== 'string') return;
    const trimmed = entry.trim();
    if (trimmed === '') return;
    unique.add(trimmed);
  });
  return Array.from(unique);
};

const HEX_COLOR_PATTERN = /^#[0-9a-fA-F]{6}$/;

const normalizeIconColorMode = (value: unknown): 'theme' | 'custom' =>
  value === 'custom' ? 'custom' : 'theme';

const normalizeIconColor = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  if (HEX_COLOR_PATTERN.test(trimmed) === false) return null;
  return trimmed.toLowerCase();
};

const openProductFormTabOptions = new Set<string>(PRODUCT_DRAFT_OPEN_FORM_TAB_OPTIONS);
const draftKindOptions = new Set<string>(PRODUCT_DRAFT_KIND_OPTIONS);

const normalizeDraftKind = (value: unknown): ProductDraftKind => {
  if (typeof value !== 'string') return 'standard';
  const trimmed = value.trim();
  if (draftKindOptions.has(trimmed) === false) return 'standard';
  return trimmed as ProductDraftKind;
};

const normalizeNullableString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const normalizeOpenProductFormTab = (value: unknown): ProductDraftOpenFormTab => {
  if (typeof value !== 'string') return 'general';
  const trimmed = value.trim();
  if (openProductFormTabOptions.has(trimmed) === false) return 'general';
  return trimmed as ProductDraftOpenFormTab;
};

const MONGO_OBJECT_ID_PATTERN = /^[0-9a-fA-F]{24}$/;

const buildDraftIdFilter = (id: string): Filter<MongoDraftDoc> => {
  const trimmed = id.trim();
  const stringMongoIdFilter: Filter<MongoDraftDoc> = { _id: trimmed };
  const domainIdFilter: Filter<MongoDraftDoc> = { id: trimmed };
  const filters: Filter<MongoDraftDoc>[] = [stringMongoIdFilter, domainIdFilter];

  if (MONGO_OBJECT_ID_PATTERN.test(trimmed) && ObjectId.isValid(trimmed)) {
    const objectIdFilter: Filter<MongoDraftDoc> = { _id: new ObjectId(trimmed) };
    filters.push(objectIdFilter);
  }

  return { $or: filters };
};

const mapMongoDocToDraft = (doc: MongoDraftDoc): ProductDraft => {
  return {
    id: String(doc.id ?? doc._id),
    name: doc.name ?? '',
    draftKind: normalizeDraftKind(doc.draftKind),
    scrapeProfileId: normalizeNullableString(doc.scrapeProfileId),
    description: doc.description ?? null,
    sku: doc.sku ?? null,
    ean: doc.ean ?? null,
    gtin: doc.gtin ?? null,
    asin: doc.asin ?? null,
    name_en: doc.name_en ?? null,
    name_pl: doc.name_pl ?? null,
    name_de: doc.name_de ?? null,
    description_en: doc.description_en ?? null,
    description_pl: doc.description_pl ?? null,
    description_de: doc.description_de ?? null,
    weight: doc.weight ?? null,
    sizeLength: doc.sizeLength ?? null,
    sizeWidth: doc.sizeWidth ?? null,
    length: doc.length ?? null,
    price: doc.price ?? null,
    supplierName: doc.supplierName ?? null,
    supplierLink: doc.supplierLink ?? null,
    priceComment: doc.priceComment ?? null,
    stock: doc.stock ?? null,
    catalogIds: Array.isArray(doc.catalogIds) ? doc.catalogIds : [],
    categoryId: typeof doc.categoryId === 'string' ? doc.categoryId : null,
    tagIds: Array.isArray(doc.tagIds) ? doc.tagIds : [],
    producerIds: normalizeStringArray(doc.producerIds),
    parameters: Array.isArray(doc.parameters) ? doc.parameters : [],
    defaultPriceGroupId: doc.defaultPriceGroupId ?? null,
    active: doc.active ?? true,
    validatorEnabled: doc.validatorEnabled ?? true,
    formatterEnabled: doc.formatterEnabled ?? false,
    icon: doc.icon ?? null,
    iconColorMode: normalizeIconColorMode(doc.iconColorMode),
    iconColor: normalizeIconColor(doc.iconColor),
    openProductFormTab: normalizeOpenProductFormTab(doc.openProductFormTab),
    imageLinks: Array.isArray(doc.imageLinks) ? doc.imageLinks : [],
    baseProductId: doc.baseProductId ?? null,
    importSource: doc.importSource ?? null,
    createdAt: (doc.createdAt ?? new Date()).toISOString(),
    updatedAt: (doc.updatedAt ?? new Date()).toISOString(),
  };
};

const listDraftsMongo = async (): Promise<ProductDraft[]> => {
  const mongo = await getMongoDb();
  const drafts = await mongo
    .collection<MongoDraftDoc>('product_drafts')
    .find({})
    .sort({ createdAt: -1 })
    .toArray();

  return drafts.map(mapMongoDocToDraft);
};

const getDraftMongo = async (id: string): Promise<ProductDraft | null> => {
  const mongo = await getMongoDb();
  const draft = await mongo
    .collection<MongoDraftDoc>('product_drafts')
    .findOne(buildDraftIdFilter(id));

  if (draft === null) return null;
  return mapMongoDocToDraft(draft);
};

const buildCreateDraftDoc = (input: CreateProductDraftInput, id: string, now: Date): MongoDraftDoc => ({
  _id: id,
  ...input,
  draftKind: normalizeDraftKind(input.draftKind),
  scrapeProfileId: normalizeNullableString(input.scrapeProfileId),
  description: input.description ?? null,
  sku: input.sku ?? null,
  ean: input.ean ?? null,
  gtin: input.gtin ?? null,
  asin: input.asin ?? null,
  name_en: input.name_en ?? null,
  name_pl: input.name_pl ?? null,
  name_de: input.name_de ?? null,
  description_en: input.description_en ?? null,
  description_pl: input.description_pl ?? null,
  description_de: input.description_de ?? null,
  weight: input.weight ?? null,
  sizeLength: input.sizeLength ?? null,
  sizeWidth: input.sizeWidth ?? null,
  length: input.length ?? null,
  price: input.price ?? null,
  supplierName: input.supplierName ?? null,
  supplierLink: input.supplierLink ?? null,
  priceComment: input.priceComment ?? null,
  stock: input.stock ?? null,
  baseProductId: input.baseProductId ?? null,
  importSource: input.importSource ?? null,
  defaultPriceGroupId: input.defaultPriceGroupId ?? null,
  catalogIds: input.catalogIds ?? [],
  categoryId: input.categoryId ?? null,
  tagIds: input.tagIds ?? [],
  producerIds: normalizeStringArray(input.producerIds),
  parameters: input.parameters ?? [],
  validatorEnabled: input.validatorEnabled ?? true,
  formatterEnabled: input.formatterEnabled ?? false,
  icon: input.icon ?? null,
  iconColorMode: normalizeIconColorMode(input.iconColorMode),
  iconColor: normalizeIconColor(input.iconColor),
  openProductFormTab: normalizeOpenProductFormTab(input.openProductFormTab),
  imageLinks: input.imageLinks ?? [],
  active: input.active ?? true,
  createdAt: now,
  updatedAt: now,
});

const createDraftMongo = async (input: CreateProductDraftInput): Promise<ProductDraft> => {
  const mongo = await getMongoDb();
  const now = new Date();
  const id = randomUUID();
  const draft = buildCreateDraftDoc(input, id, now);

  await mongo.collection<MongoDraftDoc>('product_drafts').insertOne(draft);
  return mapMongoDocToDraft(draft);
};

const updateDraftMongo = async (
  id: string,
  input: UpdateProductDraftInput
): Promise<ProductDraft | null> => {
  const mongo = await getMongoDb();
  const now = new Date();
  const updatePayload: Record<string, unknown> = {};

  (Object.keys(input) as (keyof UpdateProductDraftInput)[]).forEach(
    (key: keyof UpdateProductDraftInput) => {
      const val = input[key];
      if (val !== undefined) {
        updatePayload[key] = val;
      }
    }
  );

  if ('categoryId' in input) {
    updatePayload['categoryId'] = (typeof input.categoryId === 'string' && input.categoryId.trim() !== '')
      ? input.categoryId.trim()
      : null;
  }

  if ('draftKind' in input) {
    updatePayload['draftKind'] = normalizeDraftKind(input.draftKind);
  }

  if ('scrapeProfileId' in input) {
    updatePayload['scrapeProfileId'] = normalizeNullableString(input.scrapeProfileId);
  }

  if ('producerIds' in input) {
    updatePayload['producerIds'] = normalizeStringArray(input.producerIds);
  }

  if ('iconColorMode' in input) {
    updatePayload['iconColorMode'] = normalizeIconColorMode(input.iconColorMode);
  }

  if ('iconColor' in input) {
    updatePayload['iconColor'] = normalizeIconColor(input.iconColor);
  }

  if ('openProductFormTab' in input) {
    updatePayload['openProductFormTab'] = normalizeOpenProductFormTab(input.openProductFormTab);
  }

  const result = await mongo.collection<MongoDraftDoc>('product_drafts').findOneAndUpdate(
    buildDraftIdFilter(id),
    {
      $set: {
        ...updatePayload,
        updatedAt: now,
      },
    },
    { returnDocument: 'after' }
  );

  if (result === null) return null;

  const doc =
    (typeof result === 'object' && 'value' in result)
      ? (result.value as MongoDraftDoc | null)
      : (result as MongoDraftDoc | null);

  if (doc === null) return null;
  return mapMongoDocToDraft(doc);
};

const deleteDraftMongo = async (id: string): Promise<boolean> => {
  const mongo = await getMongoDb();
  const result = await mongo
    .collection<MongoDraftDoc>('product_drafts')
    .deleteOne(buildDraftIdFilter(id));
  return result.deletedCount > 0;
};

// Public API
export const listDrafts = async (): Promise<ProductDraft[]> => listDraftsMongo();

export const getDraft = async (id: string): Promise<ProductDraft | null> => getDraftMongo(id);

export const createDraft = async (input: CreateProductDraftInput): Promise<ProductDraft> =>
  createDraftMongo(input);

export const updateDraft = async (
  id: string,
  input: UpdateProductDraftInput
): Promise<ProductDraft | null> => updateDraftMongo(id, input);

export const deleteDraft = async (id: string): Promise<boolean> => deleteDraftMongo(id);
